// This service simulates the high-security backend interactions.
// In a real app, this would use fetch() to hit endpoints protected by Rate Limiting and WAF.

export interface AuthUser {
  id: string;
  name: string;
  phone: string;
  token: string;
}

export const authService = {
  login: async (phone: string): Promise<AuthUser> => {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Simulate input validation (Sanitization)
    const sanitizedPhone = phone.replace(/[^0-9]/g, '');

    if (sanitizedPhone.length < 9) {
      throw new Error("Número de telefone inválido.");
    }

    // In a real app, this would return a JWT after verifying SMS OTP
    return {
      id: 'current-user-id',
      name: 'Utilizador',
      phone: sanitizedPhone,
      token: 'mock-jwt-token-secure-hash'
    };
  },

  isAuthenticated: (): boolean => {
    // Check if token exists and is valid (mock)
    return !!localStorage.getItem('txova_token');
  },

  logout: () => {
    localStorage.removeItem('txova_token');
    window.location.hash = '/';
  }
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Input } from '../components/ui';
import { authService } from '../services/auth';
import { ShieldCheck, Phone } from 'lucide-react';

export const Onboarding: React.FC = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState<'welcome' | 'login'>('welcome');
  const [phone, setPhone] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleLogin = async () => {
    if (!phone) return;
    setIsLoading(true);
    try {
      const user = await authService.login(phone);
      localStorage.setItem('txova_token', user.token);
      navigate('/feed');
    } catch (error) {
      alert("Erro ao entrar. Verifique o número.");
    } finally {
      setIsLoading(false);
    }
  };

  if (step === 'welcome') {
    return (
      <div className="h-screen flex flex-col bg-white">
        {/* Hero Image Section */}
        <div className="flex-1 relative bg-brand-pink overflow-hidden flex items-end justify-center">
          <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1531123414780-f74242c2b052?q=80&w=1000&auto=format&fit=crop')] bg-cover bg-center opacity-40 mix-blend-multiply"></div>
          <div className="relative z-10 p-8 text-center pb-12 w-full">
            <div className="inline-block bg-white/20 backdrop-blur-md p-4 rounded-full mb-6 border border-white/30">
               <span className="text-4xl">🇲🇿</span>
            </div>
            <h1 className="text-4xl font-heading font-bold text-white mb-2 leading-tight">
              Txova<span className="text-brand-blue">Love</span>
            </h1>
            <p className="text-white/90 text-lg font-medium">Encontra pessoas perto de ti.</p>
          </div>
        </div>

        {/* CTA Section */}
        <div className="p-8 pb-12 bg-white rounded-t-3xl -mt-6 relative z-20 shadow-[0_-10px_40px_rgba(0,0,0,0.1)]">
          <div className="flex flex-col gap-4">
            <h2 className="text-center text-gray-800 font-heading font-bold text-xl mb-2">Bem-vindo(a)</h2>
            <Button onClick={() => setStep('login')}>
              Criar Perfil
            </Button>
            <Button variant="outline" onClick={() => setStep('login')}>
              Já tenho conta
            </Button>

            <p className="text-center text-xs text-gray-400 mt-4 leading-relaxed">
              Ao continuar, aceitas os nossos Termos e Política de Privacidade.
              <br/>Sistema 100% seguro protegido contra fraudes.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col p-6 bg-white justify-center max-w-md mx-auto">
      <div className="mb-8 text-center">
        <div className="w-16 h-16 bg-brand-pink/10 rounded-full flex items-center justify-center mx-auto mb-4 text-brand-pink">
          <ShieldCheck size={32} />
        </div>
        <h2 className="text-2xl font-heading font-bold text-gray-800">Verificação Segura</h2>
        <p className="text-gray-500 mt-2 text-sm">Nós não partilhamos o teu contacto sem a tua permissão.</p>
      </div>

      <div className="space-y-6">
        <Input 
          label="Número de WhatsApp" 
          placeholder="84 123 4567" 
          type="tel"
          icon={<Phone size={18} />}
          value={phone}
          onChange={(e) => setPhone(e.target.value)}
        />

        <div className="bg-yellow-50 border border-yellow-100 p-3 rounded-lg flex gap-2">
          <span className="text-yellow-600 mt-0.5">⚠️</span>
          <p className="text-xs text-yellow-700">Para tua segurança, enviaremos um código de confirmação. Nunca partilhes o teu código.</p>
        </div>

        <Button onClick={handleLogin} isLoading={isLoading}>
          Continuar
        </Button>

        <button onClick={() => setStep('welcome')} className="w-full text-center text-gray-400 text-sm font-medium hover:text-brand-pink">
          Voltar
        </button>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { MOCK_PROFILES, MOCK_ADS } from '../constants';
import { UserProfile, AdContent, FeedItem } from '../types';
import { Button, Badge, Modal, Input } from '../components/ui';
import { MapPin, Heart, MessageCircle, MoreVertical, Flag, Calendar, ExternalLink } from 'lucide-react';
import { PREMIUM_PLANS, REPORT_REASONS } from '../constants';

// --- Card Components (Internal) ---

const ProfileCard: React.FC<{ 
  profile: UserProfile; 
  onProposeDate: (p: UserProfile) => void; 
  onReport: (p: UserProfile) => void;
}> = ({ profile, onProposeDate, onReport }) => {
  return (
    <div className="bg-white rounded-3xl overflow-hidden shadow-sm border border-gray-100 mb-6">
      <div className="relative h-[400px]">
        <img 
          src={profile.photos[0]} 
          alt={profile.name} 
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>

        {/* Top Actions */}
        <div className="absolute top-4 right-4">
           <button onClick={() => onReport(profile)} className="p-2 bg-black/20 backdrop-blur-md rounded-full text-white hover:bg-black/40">
             <MoreVertical size={20} />
           </button>
        </div>

        {/* Bottom Info */}
        <div className="absolute bottom-0 left-0 w-full p-6 text-white">
          <div className="flex items-center gap-2 mb-1">
            <h3 className="text-3xl font-heading font-bold">{profile.name}, {profile.age}</h3>
            {profile.isVerified && <Badge type="verified">Verificado</Badge>}
          </div>
          <div className="flex items-center gap-1 text-gray-200 text-sm mb-3">
            <MapPin size={14} />
            <span>{profile.district ? `${profile.district}, ` : ''}{profile.city}</span>
          </div>
          <p className="text-gray-100 text-sm line-clamp-2 opacity-90">{profile.bio}</p>
        </div>
      </div>

      {/* Action Buttons */}
      <div className="p-4 grid grid-cols-2 gap-3 bg-white">
        <Button variant="outline" onClick={() => onProposeDate(profile)} className="text-sm">
           <Calendar size={18} />
           Encontro
        </Button>
        <Button 
          variant="primary" 
          onClick={() => {
             // Direct WhatsApp link security check
             if(window.confirm(`Abrir WhatsApp para conversar com ${profile.name}?`)) {
                 window.open(`https://wa.me/${profile.whatsappNumber}`, '_blank');
             }
          }}
          className="text-sm"
        >
          <MessageCircle size={18} />
          Conversar
        </Button>
      </div>
    </div>
  );
};

const AdCard: React.FC<{ ad: AdContent }> = ({ ad }) => {
  return (
    <div className="bg-white rounded-2xl overflow-hidden shadow-sm border border-gray-100 mb-6 mx-2">
      <div className="bg-gray-50 px-4 py-2 flex justify-between items-center border-b border-gray-100">
        <span className="text-[10px] font-bold tracking-wider text-gray-400 uppercase">Patrocinado</span>
        {ad.type === 'BUSINESS' && <span className="text-xs font-semibold text-brand-blue">Negócio Local</span>}
      </div>
      <img src={ad.imageUrl} alt={ad.title} className="w-full h-48 object-cover" />
      <div className="p-4">
        <h4 className="font-heading font-bold text-gray-800 text-lg mb-1">{ad.title}</h4>
        <p className="text-gray-500 text-sm mb-4">{ad.description}</p>
        <a 
          href={ad.ctaLink} 
          target="_blank" 
          rel="noopener noreferrer"
          className="block w-full py-3 bg-gray-900 text-white text-center rounded-xl font-semibold text-sm hover:bg-black transition-colors flex items-center justify-center gap-2"
        >
          {ad.ctaText}
          <ExternalLink size={14} />
        </a>
      </div>
    </div>
