export const Feed: React.FC = () => {
  const [selectedProfile, setSelectedProfile] = useState<UserProfile | null>(null);
  const [isDateModalOpen, setDateModalOpen] = useState(false);
  const [isReportModalOpen, setReportModalOpen] = useState(false);

  // Date Proposal State
  const [dateDetails, setDateDetails] = useState({ date: '', time: '', location: '' });

  const handleProposeDate = () => {
    if (!selectedProfile) return;
    const msg = `Olá ${selectedProfile.name}! Gostaria de te convidar para um encontro no dia ${dateDetails.date} às ${dateDetails.time} no local: ${dateDetails.location}. O que achas?`;
    const encoded = encodeURIComponent(msg);
    window.open(`https://wa.me/${selectedProfile.whatsappNumber}?text=${encoded}`, '_blank');
    setDateModalOpen(false);
  };

  const handleReport = (reasonId: string) => {
    alert("Obrigado. A denúncia foi enviada. Levamos a segurança muito a sério. O perfil será analisado por IA e moderadores humanos.");
    setReportModalOpen(false);
  };

  return (
    <div className="p-4 pt-4">
      {/* Safety Header */}
      <div className="bg-blue-50 border border-blue-100 p-3 rounded-xl mb-6 flex items-start gap-3">
        <div className="bg-blue-100 p-2 rounded-full text-blue-600">
          <ShieldCheck size={18} />
        </div>
        <div>
          <h3 className="text-sm font-bold text-blue-800">Área Segura</h3>
          <p className="text-xs text-blue-600 leading-relaxed">
            Aqui só encontras pessoas reais. Fotos de famosos, paisagens ou desenhos são removidas automaticamente.
          </p>
        </div>
      </div>

      <div className="flex items-center justify-between mb-4 px-2">
        <h2 className="font-heading font-bold text-2xl text-gray-800">Pessoas Reais</h2>
        <button className="flex items-center gap-1 text-sm font-semibold text-brand-pink">
          <MapPin size={16} />
          Maputo
        </button>
      </div>

      {MOCK_PROFILES.map((profile) => (
        <ProfileCard 
          key={profile.id}
          profile={profile} 
          onProposeDate={(p) => { setSelectedProfile(p); setDateModalOpen(true); }}
          onReport={(p) => { setSelectedProfile(p); setReportModalOpen(true); }}
        />
      ))}

      {/* Date Proposal Modal */}
      <Modal isOpen={isDateModalOpen} onClose={() => setDateModalOpen(false)} title="Marcar Encontro">
        <div className="space-y-4">
          <p className="text-sm text-gray-500">Propõe uma data. Se a pessoa aceitar, vocês combinam os detalhes no WhatsApp.</p>
          <Input 
             label="Data" 
             type="date" 
             value={dateDetails.date} 
             onChange={e => setDateDetails({...dateDetails, date: e.target.value})}
          />
          <Input 
             label="Hora" 
             type="time" 
             value={dateDetails.time}
             onChange={e => setDateDetails({...dateDetails, time: e.target.value})}
          />
          <Input 
             label="Local Sugerido" 
             placeholder="Ex: Restaurante O Marisco" 
             value={dateDetails.location}
             onChange={e => setDateDetails({...dateDetails, location: e.target.value})}
          />
          <Button onClick={handleProposeDate}>Enviar Convite</Button>
        </div>
      </Modal>

      {/* Report Modal */}
      <Modal isOpen={isReportModalOpen} onClose={() => setReportModalOpen(false)} title="Denunciar Perfil">
        <div className="space-y-2">
           <p className="text-sm text-gray-500 mb-4">Se suspeitares que a foto não é real, denuncia imediatamente.</p>
           {REPORT_REASONS.map(reason => (
             <button 
               key={reason.id}
               onClick={() => handleReport(reason.id)}
               className="w-full text-left p-3 rounded-lg hover:bg-red-50 text-gray-700 hover:text-red-600 text-sm font-medium border border-transparent hover:border-red-100 transition-colors flex items-center justify-between"
             >
               {reason.label}
               <Flag size={14} />
             </button>
           ))}
        </div>
      </Modal>
    </div>
  );
};

