// This service simulates the high-security backend interactions.
// In a real app, this would use fetch() to hit endpoints protected by Rate Limiting and WAF.

export interface AuthUser {
  id: string;
  name: string;
  phone: string;
  token: string;
  province?: string;
  photoUrl?: string;
}

export interface RegisterData {
  name: string;
  phone: string;
  password: string;
  province: string;
  photo: File;
}

export const authService = {
  login: async (phone: string, password?: string): Promise<AuthUser> => {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Simulate input validation (Sanitization)
    const sanitizedPhone = phone.replace(/[^0-9]/g, '');

    if (sanitizedPhone.length < 9) {
      throw new Error("Número de telefone inválido.");
    }

    // In real app: verify password hash
    if (password && password.length < 4) {
      throw new Error("Palavra-passe incorreta.");
    }

    // In a real app, this would return a JWT after verifying SMS OTP or Password
    return {
      id: 'current-user-id',
      name: 'Utilizador',
      phone: sanitizedPhone,
      token: 'mock-jwt-token-secure-hash',
      province: 'Maputo Cidade' // Default for existing users mock
    };
  },

  register: async (data: RegisterData): Promise<AuthUser> => {
    // Simulate API upload delay
    await new Promise(resolve => setTimeout(resolve, 2500));

    // Validate
    if (!data.name || !data.password || !data.photo || !data.province) {
      throw new Error("Dados incompletos.");
    }

    const sanitizedPhone = data.phone.replace(/[^0-9]/g, '');

    // Simulate backend response
    return {
      id: 'new-user-id',
      name: data.name,
      phone: sanitizedPhone,
      token: 'mock-new-user-token',
      province: data.province,
      photoUrl: URL.createObjectURL(data.photo) // Mock URL for local preview
    };
  },

  isAuthenticated: (): boolean => {
    // Check if token exists and is valid (mock)
    return !!localStorage.getItem('txova_token');
  },

  logout: () => {
    localStorage.removeItem('txova_token');
    window.location.hash = '/';
  }
};

