      </div>

      <div className="space-y-4">
        {/* Register Fields */}
        {authMode === 'register' && (
          <>
            <Input 
              name="name"
              label="Nome Completo" 
              placeholder="Ex: Neyma Silva" 
              icon={<User size={18} />}
              value={formData.name}
              onChange={handleInputChange}
            />

            <Select 
               name="province"
               label="Província"
               options={PROVINCES}
               value={formData.province}
               onChange={handleInputChange}
            />

            <ImageUpload 
              label="Foto de Perfil (Obrigatório)"
              previewUrl={formData.photoPreview}
              onImageSelect={handlePhotoSelect}
            />
