        {/* Common Fields */}
        <Input 
          name="phone"
          label="Número de Telemóvel" 
          placeholder="84 123 4567" 
          type="tel"
          icon={<Phone size={18} />}
          value={formData.phone}
          onChange={handleInputChange}
