// Blacklist of terms for immediate blocking (Text)
const BANNED_KEYWORDS = [
  'nude', 'sexo', 'xxx', 'porn', 'prostituta', 'programa', 
  'intimo', 'dotado', 'safada', 'safado', 'quente', 
  'massagem erotica', 'acompanhante', 'sugar', 'pix'
];

export const safetyService = {
  /**
   * Analyzes text for prohibited content.
   */
  analyzeText: (text: string): boolean => {
    if (!text) return true;
    const lowerText = text.toLowerCase();

    // Check for banned keywords
    const hasBannedWord = BANNED_KEYWORDS.some(word => lowerText.includes(word));

    if (hasBannedWord) {
      console.warn(`Safety System: Blocked text containing banned content.`);
      return false;
    }

    return true;
  },

  /**
   * Simulates AI Image Analysis for Nudity/Gore/Violence.
   * In a real app, this sends the image to a backend API.
   */
  analyzeImage: async (file: File): Promise<boolean> => {
    // Simulate AI Processing Delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // MOCK LOGIC FOR DEMONSTRATION:
    // If the file name contains "xxx", "nude", or "sexy", we simulate a flag.
    // In production, this analyzes the actual PIXELS of the image.
    const fileName = file.name.toLowerCase();
    if (fileName.includes('xxx') || fileName.includes('nude') || fileName.includes('porn') || fileName.includes('sex')) {
      console.warn(`Safety System: AI detected explicit content in image.`);
      return false; // REJECT
    }

    // Default: Approve (Clean)
    return true;
  },

  /**
   * Checks if the user is currently suspended.
   */
  checkUserStanding: (userId: string): 'ACTIVE' | 'SUSPENDED' | 'BANNED' => {
    // Mock check
    return 'ACTIVE';
  }
};

import { safetyService, SAFETY_ERROR_MSG } from './safety';

// This service simulates the high-security backend interactions.
// In a real app, this would use fetch() to hit endpoints protected by Rate Limiting and WAF.

export interface AuthUser {
  id: string;
  name: string;
  phone: string;
  token: string;
  province?: string;
  photoUrl?: string;
  bio?: string;
}

export interface RegisterData {
  name: string;
  phone: string;
  password: string;
  province: string;
  photo: File;
  bio?: string;
}

export const authService = {
  login: async (phone: string, password?: string): Promise<AuthUser> => {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Simulate input validation (Sanitization)
    const sanitizedPhone = phone.replace(/[^0-9]/g, '');

    if (sanitizedPhone.length < 9) {
      throw new Error("Número de telefone inválido.");
    }

    // In real app: verify password hash
    if (password && password.length < 4) {
      throw new Error("Palavra-passe incorreta.");
    }

    // In a real app, this would return a JWT after verifying SMS OTP or Password
    return {
      id: 'current-user-id',
      name: 'Utilizador',
      phone: sanitizedPhone,
      token: 'mock-jwt-token-secure-hash',
      province: 'Maputo Cidade' // Default for existing users mock
    };
  },

  register: async (data: RegisterData): Promise<AuthUser> => {
    // 1. SAFETY CHECK (TEXT)
    // Check Name and potential Bio for banned words
    if (!safetyService.analyzeText(data.name)) {
      throw new Error(SAFETY_ERROR_MSG);
    }

    if (data.bio && !safetyService.analyzeText(data.bio)) {
      throw new Error(SAFETY_ERROR_MSG);
    }

    // Simulate API upload delay (Uploading + AI Analysis)
    await new Promise(resolve => setTimeout(resolve, 2000));

    // 2. SAFETY CHECK (IMAGE)
    // Analyze the uploaded photo
    const isImageSafe = await safetyService.analyzeImage(data.photo);
    if (!isImageSafe) {
       // Log the attempt in backend for potential ban
       console.error("User attempted to upload explicit content. Flagging account.");
       throw new Error(SAFETY_ERROR_MSG);
    }

    // Validate
    if (!data.name || !data.password || !data.photo || !data.province) {
      throw new Error("Dados incompletos.");
    }

    const sanitizedPhone = data.phone.replace(/[^0-9]/g, '');

    // Simulate backend response
    return {
      id: 'new-user-id',
      name: data.name,
      phone: sanitizedPhone,
      token: 'mock-new-user-token',
      province: data.province,
      photoUrl: URL.createObjectURL(data.photo) // Mock URL for local preview
    };
  },

  isAuthenticated: (): boolean => {
    // Check if token exists and is valid (mock)
    return !!localStorage.getItem('txova_token');
  },

  logout: () => {
    localStorage.removeItem('txova_token');
    window.location.hash = '/';
  }
};

