import React, { useState, useRef } from 'react';
import { Button, Modal } from '../components/ui';
import { authService } from '../services/auth';
import { safetyService, SAFETY_ERROR_MSG } from '../services/safety';
import { Settings, LogOut, Edit2, Shield, CreditCard, Camera, Check, AlertOctagon } from 'lucide-react';

export const Profile: React.FC = () => {
  // Mock User
  const [user, setUser] = useState({
    name: 'Utilizador',
    phone: '84 123 4567',
    photos: ['https://picsum.photos/400/400'],
    isPremium: false,
    isVerified: false
  });

  const [showVerification, setShowVerification] = useState(false);
  const [verifyingStep, setVerifyingStep] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleLogout = () => {
    if(window.confirm("Tens a certeza que queres sair?")) {
      authService.logout();
    }
  };

  const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setIsUploading(true);

      try {
        // CONTENT SAFETY CHECK
        const isSafe = await safetyService.analyzeImage(file);

        if (!isSafe) {
          alert(SAFETY_ERROR_MSG + "\n\nSua conta foi sinalizada por tentar enviar conteúdo impróprio.");
          return;
        }

        // Simulating upload success
        const newUrl = URL.createObjectURL(file);
        setUser({...user, photos: [newUrl]});
        alert("Foto atualizada com sucesso!");
      } catch (err) {
        alert("Erro ao processar imagem.");
      } finally {
        setIsUploading(false);
      }
    }
  };

  const startVerification = () => {
    setVerifyingStep(1);
    // Simulate Face Scan
    setTimeout(() => {
        setVerifyingStep(2);
    }, 2000);
    setTimeout(() => {
        setUser({...user, isVerified: true});
        setShowVerification(false);
        setVerifyingStep(0);
        alert("Verificação concluída com sucesso! Agora tens o selo de autenticidade.");
    }, 4000);
  };

  return (
    <div className="pb-8">
      {/* Header Image */}
      <div className="h-48 bg-gray-200 relative">
        <img src="https://images.unsplash.com/photo-1550993030-80a581457193?auto=format&fit=crop&q=80&w=1000" className="w-full h-full object-cover opacity-80" alt="Cover" />
        <div className="absolute -bottom-12 left-1/2 -translate-x-1/2">
          <div 
             onClick={() => fileInputRef.current?.click()}
             className="w-24 h-24 rounded-full border-4 border-white bg-gray-300 overflow-hidden shadow-md relative group cursor-pointer"
          >
            <img src={user.photos[0]} alt="Profile" className={`w-full h-full object-cover ${isUploading ? 'opacity-50' : ''}`} />

            {isUploading ? (
               <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
               </div>
            ) : (
               <div className="absolute inset-0 bg-black/30 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                  <Camera className="text-white" size={24} />
               </div>
            )}

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*"
              onChange={handlePhotoUpload}
            />
          </div>
        </div>
      </div>

      {/* Info */}
      <div className="mt-14 text-center px-6">
        <div className="flex items-center justify-center gap-2">
            <h2 className="text-2xl font-heading font-bold text-gray-800">{user.name}</h2>
            {user.isVerified && <div className="text-blue-500"><Shield size={20} fill="currentColor" /></div>}
        </div>
        <p className="text-gray-500 text-sm font-medium mt-1">+258 {user.phone}</p>

        {!user.isVerified && (
            <button 
              onClick={() => setShowVerification(true)}
              className="mt-4 flex items-center gap-2 mx-auto bg-blue-50 text-blue-600 px-4 py-2 rounded-full text-xs font-bold border border-blue-100 animate-pulse"
            >
              <Shield size={12} />
              Verificar Perfil Agora
            </button>
        )}
      </div>

      {/* Settings List */}
      <div className="mt-8 px-4 space-y-3">
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <button className="w-full flex items-center gap-3 p-4 hover:bg-gray-50 transition-colors text-left border-b border-gray-50">
            <div className="bg-gray-100 text-gray-600 p-2 rounded-lg">
               <Edit2 size={20} />
            </div>
            <span className="font-medium text-gray-700 flex-1">Editar Fotos</span>
          </button>

          <button className="w-full flex items-center gap-3 p-4 hover:bg-gray-50 transition-colors text-left border-b border-gray-50">
            <div className="bg-gray-100 text-gray-600 p-2 rounded-lg">
               <Settings size={20} />
            </div>
            <span className="font-medium text-gray-700 flex-1">Preferências</span>
          </button>

          <button onClick={handleLogout} className="w-full flex items-center gap-3 p-4 hover:bg-red-50 transition-colors text-left text-red-600">
            <div className="bg-red-50 text-red-500 p-2 rounded-lg">
               <LogOut size={20} />
            </div>
            <span className="font-medium flex-1">Sair da conta</span>
          </button>
        </div>

        <div className="text-center text-xs text-gray-300 mt-8">
          <p>Txova Love v1.0.0 (Secure)</p>
          <p>Feito com ❤️ em Moçambique</p>
        </div>
      </div>

      {/* Verification Modal */}
      <Modal isOpen={showVerification} onClose={() => { if(verifyingStep === 0) setShowVerification(false)}} title="Verificação Facial">
        <div className="text-center py-4">
            {verifyingStep === 0 && (
                <>
                    <div className="w-20 h-20 bg-gray-100 rounded-full mx-auto flex items-center justify-center mb-4">
                        <Camera size={40} className="text-gray-400" />
                    </div>
                    <h3 className="font-bold text-lg mb-2">Vamos verificar se és tu</h3>
                    <p className="text-gray-500 text-sm mb-6">
                        Para garantir a segurança de todos, precisamos de comparar uma selfie tua com as tuas fotos de perfil.
                    </p>
                    <Button onClick={startVerification}>Tirar Selfie</Button>
                </>
            )}
            {verifyingStep === 1 && (
                <>
                    <div className="w-20 h-20 bg-blue-50 rounded-full mx-auto flex items-center justify-center mb-4 animate-bounce">
                        <Camera size={40} className="text-blue-500" />
                    </div>
                    <h3 className="font-bold text-lg mb-2">A analisar...</h3>
                    <p className="text-gray-500 text-sm">Olha para a câmara e não te mexas.</p>
                </>
            )}
            {verifyingStep === 2 && (
                <>
                    <div className="w-20 h-20 bg-green-50 rounded-full mx-auto flex items-center justify-center mb-4">
                        <Check size={40} className="text-green-500" />
                    </div>
                    <h3 className="font-bold text-lg mb-2">Verificado!</h3>
                    <p className="text-gray-500 text-sm">O teu perfil agora é 100% seguro.</p>
                </>
            )}
        </div>
      </Modal>
    </div>
  );
};

