import { Message, ChatSession, UserProfile } from '../types';
import { MOCK_PROFILES } from '../constants';

// Mock storage for chats
// In a real app, this would be a database
let MOCK_MESSAGES: Record<string, Message[]> = {
  'u1': [
    { id: 'm1', text: 'Olá! Vi que gostas de Marrabenta também.', senderId: 'u1', timestamp: Date.now() - 10000000, isRead: true },
    { id: 'm2', text: 'Sim! Adoro. Costumas ir a concertos?', senderId: 'me', timestamp: Date.now() - 9000000, isRead: true },
    { id: 'm3', text: 'Sempre que posso no Centro Cultural.', senderId: 'u1', timestamp: Date.now() - 800000, isRead: false }
  ],
  'u2': [
    { id: 'm4', text: 'Boas, tudo bem?', senderId: 'me', timestamp: Date.now() - 3600000, isRead: true },
    { id: 'm5', text: 'Tudo tranquilo e contigo?', senderId: 'u2', timestamp: Date.now() - 3500000, isRead: true }
  ]
};

export const chatService = {
  getChats: (): ChatSession[] => {
    const sessions: ChatSession[] = [];

    Object.keys(MOCK_MESSAGES).forEach(userId => {
      const user = MOCK_PROFILES.find(p => p.id === userId);
      if (!user) return;

      const msgs = MOCK_MESSAGES[userId];
      const lastMsg = msgs[msgs.length - 1];

      sessions.push({
        userId: user.id,
        userName: user.name,
        userPhoto: user.photos[0],
        lastMessage: lastMsg.text,
        lastMessageTime: lastMsg.timestamp,
        unreadCount: msgs.filter(m => !m.isRead && m.senderId !== 'me').length
      });
    });

    return sessions.sort((a, b) => b.lastMessageTime - a.lastMessageTime);
  },

  getMessages: (userId: string): Message[] => {
    return MOCK_MESSAGES[userId] || [];
  },

  sendMessage: (userId: string, text: string) => {
    if (!MOCK_MESSAGES[userId]) {
      MOCK_MESSAGES[userId] = [];
    }

    const newMessage: Message = {
      id: Date.now().toString(),
      text,
      senderId: 'me',
      timestamp: Date.now(),
      isRead: true
    };

    MOCK_MESSAGES[userId].push(newMessage);

    // Simulate auto-reply after 2 seconds to make it feel alive
    setTimeout(() => {
      const reply: Message = {
        id: (Date.now() + 1).toString(),
        text: "Obrigado pela mensagem! 😊 (Resposta automática)",
        senderId: userId,
        timestamp: Date.now(),
        isRead: false
      };
      MOCK_MESSAGES[userId].push(reply);
      // In a real app we would trigger a re-render or use a subscription
    }, 2000);
  },

  markAsRead: (userId: string) => {
    if (MOCK_MESSAGES[userId]) {
      MOCK_MESSAGES[userId].forEach(m => {
        if (m.senderId !== 'me') m.isRead = true;
      });
    }
  }
};

