export const Feed: React.FC = () => {
  const navigate = useNavigate();
  const [selectedProfile, setSelectedProfile] = useState<UserProfile | null>(null);
  const [isDateModalOpen, setDateModalOpen] = useState(false);
  const [isReportModalOpen, setReportModalOpen] = useState(false);

  // Location Filter State
  const [currentLocation, setCurrentLocation] = useState('Todas as Províncias');
  const [showLocationModal, setShowLocationModal] = useState(false);

  // Date Proposal State
  const [dateDetails, setDateDetails] = useState({ date: '', time: '', location: '' });

  // Load user preference on mount
  useEffect(() => {
    const saved = localStorage.getItem('txova_user_province');
    if (saved) setCurrentLocation(saved);
  }, []);

  const handleProposeDate = () => {
    if (!selectedProfile) return;
    const msg = `Olá ${selectedProfile.name}! Gostaria de te convidar para um encontro no dia ${dateDetails.date} às ${dateDetails.time} no local: ${dateDetails.location}. O que achas?`;

    // Send message internally
    chatService.sendMessage(selectedProfile.id, msg);

    setDateModalOpen(false);
    // Redirect to internal chat
    navigate(`/chat/${selectedProfile.id}`);
  };

  const handleReport = (reasonId: string) => {
    alert("Obrigado. A denúncia foi enviada. Levamos a segurança muito a sério. O perfil será analisado por IA e moderadores humanos.");
    setReportModalOpen(false);
  };

  const filteredProfiles = MOCK_PROFILES.filter(profile => {
    if (currentLocation === 'Todas as Províncias') return true;
    return profile.city.includes(currentLocation) || (currentLocation.includes('Maputo') && profile.city.includes('Maputo'));
  });

  return (
    <div className="p-4 pt-4">
      <div className="flex items-center justify-between mb-4 px-2">
        <h2 className="font-heading font-bold text-2xl text-gray-800">Pessoas Reais</h2>

        <button 
          onClick={() => setShowLocationModal(true)}
          className="flex items-center gap-1 text-xs font-semibold text-brand-pink bg-pink-50 px-3 py-1.5 rounded-full border border-pink-100"
        >
          <MapPin size={14} />
          <span className="max-w-[100px] truncate">{currentLocation}</span>
          <ChevronDown size={14} />
        </button>
      </div>

      {filteredProfiles.length > 0 ? (
        filteredProfiles.map((profile) => (
          <ProfileCard 
            key={profile.id}
            profile={profile} 
            onProposeDate={(p) => { setSelectedProfile(p); setDateModalOpen(true); }}
            onReport={(p) => { setSelectedProfile(p); setReportModalOpen(true); }}
            onChat={(p) => navigate(`/chat/${p.id}`)}
          />
        ))
      ) : (
        <div className="text-center py-12 text-gray-400">
          <p>Ninguém encontrado em {currentLocation} por enquanto.</p>
          <button onClick={() => setCurrentLocation('Todas as Províncias')} className="text-brand-pink underline text-sm mt-2">
            Ver todas as províncias
          </button>
        </div>
      )}

      {/* Date Proposal Modal */}
      <Modal isOpen={isDateModalOpen} onClose={() => setDateModalOpen(false)} title="Marcar Encontro">
        <div className="space-y-4">
          <p className="text-sm text-gray-500">Propõe uma data. O convite será enviado por chat privado.</p>
          <Input 
             label="Data" 
             type="date" 
             value={dateDetails.date} 
             onChange={e => setDateDetails({...dateDetails, date: e.target.value})}
          />
          <Input 
             label="Hora" 
             type="time" 
             value={dateDetails.time}
             onChange={e => setDateDetails({...dateDetails, time: e.target.value})}
          />
          <Input 
             label="Local Sugerido" 
             placeholder="Ex: Restaurante O Marisco" 
             value={dateDetails.location}
             onChange={e => setDateDetails({...dateDetails, location: e.target.value})}
          />
          <Button onClick={handleProposeDate}>Enviar Convite</Button>
        </div>
      </Modal>

      {/* Location Modal */}
      <Modal isOpen={showLocationModal} onClose={() => setShowLocationModal(false)} title="Selecionar Localização">
        <div className="grid grid-cols-1 gap-2 max-h-[60vh] overflow-y-auto">
           <button 
             onClick={() => { setCurrentLocation('Todas as Províncias'); setShowLocationModal(false); }}
             className={`p-3 rounded-xl text-left font-medium ${currentLocation === 'Todas as Províncias' ? 'bg-brand-pink text-white' : 'bg-gray-50 text-gray-700 hover:bg-gray-100'}`}
           >
             Todas as Províncias
           </button>
           {PROVINCES.map(prov => (
             <button 
               key={prov}
               onClick={() => { setCurrentLocation(prov); setShowLocationModal(false); }}
               className={`p-3 rounded-xl text-left font-medium ${currentLocation === prov ? 'bg-brand-pink text-white' : 'bg-gray-50 text-gray-700 hover:bg-gray-100'}`}
             >
               {prov}
             </button>
           ))}
        </div>
      </Modal>

      {/* Report Modal */}
      <Modal isOpen={isReportModalOpen} onClose={() => setReportModalOpen(false)} title="Denunciar Perfil">
        <div className="space-y-2">
           <p className="text-sm text-gray-500 mb-4">Se suspeitares que a foto não é real, denuncia imediatamente.</p>
           {REPORT_REASONS.map(reason => (
             <button 
               key={reason.id}
               onClick={() => handleReport(reason.id)}
               className="w-full text-left p-3 rounded-lg hover:bg-red-50 text-gray-700 hover:text-red-600 text-sm font-medium border border-transparent hover:border-red-100 transition-colors flex items-center justify-between"
             >
               {reason.label}
               <Flag size={14} />
             </button>
           ))}
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Send, MoreVertical, ShieldCheck } from 'lucide-react';
import { chatService } from '../services/chat';
import { Message } from '../types';
import { MOCK_PROFILES } from '../constants';

export const ChatScreen: React.FC = () => {
  const { userId } = useParams<{ userId: string }>();
  const navigate = useNavigate();
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const user = MOCK_PROFILES.find(p => p.id === userId);

  const loadMessages = () => {
    if (userId) {
      const msgs = chatService.getMessages(userId);
      setMessages([...msgs]); // Create copy to trigger render
      chatService.markAsRead(userId);
    }
  };

  useEffect(() => {
    loadMessages();

    // Simple poll to check for replies
    const interval = setInterval(loadMessages, 1000);
    return () => clearInterval(interval);
  }, [userId]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim() || !userId) return;

    chatService.sendMessage(userId, inputText);
    setInputText('');
    loadMessages();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  if (!user) return <div className="p-4">Utilizador não encontrado.</div>;

  return (
    <div className="flex flex-col h-screen bg-[#e5ddd5]">
      {/* Header */}
      <header className="bg-brand-pink text-white px-4 py-3 flex items-center gap-3 shadow-md z-10">
        <button onClick={() => navigate(-1)} className="p-1 hover:bg-white/10 rounded-full">
          <ArrowLeft size={24} />
        </button>

        <div className="relative w-10 h-10">
          <img src={user.photos[0]} alt={user.name} className="w-full h-full rounded-full object-cover border border-white/30" />
          <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-400 border-2 border-brand-pink rounded-full"></div>
        </div>

        <div className="flex-1">
          <h1 className="font-bold text-base leading-none flex items-center gap-1">
            {user.name}
            {user.isVerified && <ShieldCheck size={14} className="text-blue-200" />}
          </h1>
          <p className="text-xs text-white/80">Online agora</p>
        </div>

        <button className="p-2 hover:bg-white/10 rounded-full">
           <MoreVertical size={20} />
        </button>
      </header>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-3">
        {messages.length === 0 && (
          <div className="text-center py-8">
            <div className="bg-white/50 inline-block px-4 py-2 rounded-lg text-xs text-gray-600 shadow-sm">
              Inicia a conversa com {user.name} de forma segura.
            </div>
          </div>
        )}

        {messages.map((msg) => {
          const isMe = msg.senderId === 'me';
          return (
            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
              <div 
                className={`max-w-[80%] rounded-lg px-3 py-2 text-sm shadow-sm relative ${
                  isMe 
                    ? 'bg-[#dcf8c6] text-gray-800 rounded-tr-none' 
                    : 'bg-white text-gray-800 rounded-tl-none'
                }`}
              >
                <p className="whitespace-pre-wrap leading-snug">{msg.text}</p>
                <div className="text-[10px] text-gray-400 text-right mt-1 flex justify-end gap-1">
                  {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  {isMe && (
                     <span className={msg.isRead ? "text-blue-500" : "text-gray-400"}>✓✓</span>
                  )}
                </div>
              </div>
            </div>
          );
        })}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="bg-white p-2 px-3 flex items-end gap-2 border-t border-gray-200 safe-area-bottom">
         <div className="flex-1 bg-gray-100 rounded-2xl px-4 py-2 min-h-[44px] flex items-center">
            <input 
              className="w-full bg-transparent outline-none text-sm text-gray-800 max-h-32 resize-none"
              placeholder="Escreve uma mensagem..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              onKeyDown={handleKeyDown}
              autoFocus
            />
         </div>
         <button 
           onClick={handleSend}
           disabled={!inputText.trim()}
           className="w-11 h-11 bg-brand-pink text-white rounded-full flex items-center justify-center shadow-lg disabled:opacity-50 disabled:shadow-none hover:scale-105 transition-transform"
         >
           <Send size={20} className="ml-0.5" />
         </button>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { MessageCircle, Search } from 'lucide-react';
import { chatService } from '../services/chat';
import { ChatSession } from '../types';

export const Messages: React.FC = () => {
  const navigate = useNavigate();
  const [chats, setChats] = useState<ChatSession[]>([]);

  useEffect(() => {
    // Load chats on mount (and everytime we enter this screen)
    setChats(chatService.getChats());
  }, []);

  return (
    <div className="p-4 pt-6">
      <div className="flex justify-between items-end mb-6">
        <h2 className="text-2xl font-heading font-bold text-gray-800">Mensagens</h2>
        <span className="text-xs font-bold text-brand-pink bg-pink-50 px-2 py-1 rounded-lg">
          {chats.reduce((acc, chat) => acc + chat.unreadCount, 0)} novas
        </span>
      </div>

      <div className="relative mb-6">
        <input 
          placeholder="Pesquisar conversas..." 
          className="w-full bg-gray-100 border-none rounded-xl py-3 pl-10 pr-4 text-sm focus:ring-2 ring-brand-pink/20 outline-none"
        />
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
      </div>

      <div className="space-y-2">
        {chats.map(chat => (
           <div 
              key={chat.userId} 
              onClick={() => navigate(`/chat/${chat.userId}`)}
              className="flex items-center gap-3 bg-white p-3 rounded-2xl active:bg-gray-50 transition-colors cursor-pointer"
           >
              <div className="relative">
                <img src={chat.userPhoto} className="w-14 h-14 rounded-full object-cover" alt={chat.userName} />
                {chat.unreadCount > 0 && (
                   <div className="absolute top-0 right-0 w-5 h-5 bg-brand-pink text-white text-[10px] font-bold flex items-center justify-center rounded-full border-2 border-white">
                      {chat.unreadCount}
                   </div>
                )}
              </div>
              <div className="flex-1 min-w-0">
                 <div className="flex justify-between items-baseline mb-1">
                    <h4 className={`text-base truncate ${chat.unreadCount > 0 ? 'font-bold text-gray-900' : 'font-semibold text-gray-700'}`}>
                      {chat.userName}
                    </h4>
                    <span className="text-[10px] text-gray-400 shrink-0">
                      {new Date(chat.lastMessageTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </span>
                 </div>
                 <p className={`text-sm truncate ${chat.unreadCount > 0 ? 'text-gray-900 font-medium' : 'text-gray-500'}`}>
                    {chat.lastMessage}
                 </p>
              </div>
           </div>
        ))}

        {chats.length === 0 && (
           <div className="text-center py-16 text-gray-400">
              <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
                 <MessageCircle size={32} className="opacity-50" />
              </div>
              <p className="text-sm">Ainda não tens mensagens.</p>
              <p className="text-xs mt-1">Dá match ou envia um convite para começar!</p>
           </div>
        )}
      </div>
    </div>
  )
};

import React from 'react';
import { User, Heart, MessageCircle, GalleryVerticalEnd } from 'lucide-react';
import { useLocation, Link } from 'react-router-dom'; // We will use HashRouter

interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const location = useLocation();

  // Hide nav on onboarding and chat screen (full screen experience)
  if (location.pathname === '/' || location.pathname === '/onboarding' || location.pathname.startsWith('/chat/')) {
    return <main className="min-h-screen bg-white">{children}</main>;
  }

  const navItems = [
    { icon: <GalleryVerticalEnd size={24} />, label: 'Match', path: '/feed' },
    { icon: <Heart size={24} />, label: 'Curtidas', path: '/likes' },
    { icon: <MessageCircle size={24} />, label: 'Mensagens', path: '/messages' },
    { icon: <User size={24} />, label: 'Perfil', path: '/profile' },
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex justify-center">
      {/* Mobile container simulation */}
      <div className="w-full max-w-md bg-white min-h-screen shadow-2xl flex flex-col relative">

        {/* Header - Simple Logo */}
        <header className="sticky top-0 z-30 bg-white/95 backdrop-blur-md px-4 py-3 border-b border-gray-100 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-brand-pink flex items-center justify-center text-white font-bold">T</div>
            <h1 className="font-heading font-bold text-xl tracking-tight text-brand-dark">Txova<span className="text-brand-pink">Love</span></h1>
          </div>
          {/* Security Indicator */}
          <div className="text-xs text-green-600 flex items-center gap-1 bg-green-50 px-2 py-1 rounded-full border border-green-100">
             <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="11" x="3" y="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
             Seguro
          </div>
        </header>

        {/* Content */}
        <main className="flex-1 pb-24 overflow-y-auto no-scrollbar">
          {children}
        </main>

        {/* Bottom Nav */}
        <nav className="fixed bottom-0 w-full max-w-md bg-white border-t border-gray-100 px-6 py-3 pb-safe flex justify-between items-center z-40">
          {navItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link 
                key={item.path} 
                to={item.path}
                className={`flex flex-col items-center gap-1 transition-colors ${isActive ? 'text-brand-pink' : 'text-gray-400 hover:text-gray-600'}`}
              >
                {item.icon}
                <span className="text-[10px] font-medium">{item.label}</span>
              </Link>
            )
          })}
        </nav>
      </div>
    </div>
  );
};

