export const ChatScreen: React.FC = () => {
  const { userId } = useParams<{ userId: string }>();
  const navigate = useNavigate();
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [showMenu, setShowMenu] = useState(false);
  const [isReportModalOpen, setReportModalOpen] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const user = MOCK_PROFILES.find(p => p.id === userId);

  const loadMessages = () => {
    if (userId) {
      const msgs = chatService.getMessages(userId);
      setMessages([...msgs]); // Create copy to trigger render
      chatService.markAsRead(userId);
    }
  };

  useEffect(() => {
    loadMessages();

    // Simple poll to check for replies
    const interval = setInterval(loadMessages, 1000);
    return () => clearInterval(interval);
  }, [userId]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSend = () => {
    if (!inputText.trim() || !userId) return;

    chatService.sendMessage(userId, inputText);
    setInputText('');
    loadMessages();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleAction = (action: 'report' | 'block' | 'clear') => {
    setShowMenu(false);
    if (action === 'report') {
      setReportModalOpen(true);
    } else if (action === 'block') {
      if(window.confirm(`Tem a certeza que deseja bloquear ${user?.name}?`)) {
         alert("Utilizador bloqueado.");
         navigate('/feed');
      }
    } else if (action === 'clear') {
      // In a real app, calls service to clear
      alert("Conversa limpa (simulação).");
      setMessages([]);
    }
