import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { MOCK_PROFILES, PROVINCES } from '../constants';
import { UserProfile } from '../types';
import { Button, Badge, Modal, Input } from '../components/ui';
import { MapPin, MessageCircle, MoreVertical, Flag, Calendar, ShieldCheck, ChevronDown, X, Heart } from 'lucide-react';
import { REPORT_REASONS } from '../constants';
import { chatService } from '../services/chat';

const ProfileCard: React.FC<{ 
  profile: UserProfile; 
  onProposeDate: (p: UserProfile) => void; 
  onReport: (p: UserProfile) => void;
  onChat: (p: UserProfile) => void;
  onDiscard: (p: UserProfile) => void;
  isTop: boolean;
}> = ({ profile, onProposeDate, onReport, onChat, onDiscard, isTop }) => {
  // Swipe State
  const [drag, setDrag] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);
  const startPos = useRef({ x: 0, y: 0 });

  // Touch Handlers
  const handleStart = (clientX: number, clientY: number) => {
    if (!isTop) return;
    setIsDragging(true);
    startPos.current = { x: clientX, y: clientY };
  };

  const handleMove = (clientX: number, clientY: number) => {
    if (!isDragging || !isTop) return;
    const deltaX = clientX - startPos.current.x;
    const deltaY = clientY - startPos.current.y;
    setDrag({ x: deltaX, y: deltaY });
  };

  const handleEnd = () => {
    if (!isTop) return;
    setIsDragging(false);

    const threshold = 100; // px to trigger action

    if (drag.x > threshold) {
      // Swipe Right -> Like/Chat
      onChat(profile);
    } else if (drag.x < -threshold) {
      // Swipe Left -> Discard
      onDiscard(profile);
    } else {
      // Reset
      setDrag({ x: 0, y: 0 });
    }
  };

  // Mouse/Touch Events
  const onTouchStart = (e: React.TouchEvent) => handleStart(e.touches[0].clientX, e.touches[0].clientY);
  const onTouchMove = (e: React.TouchEvent) => handleMove(e.touches[0].clientX, e.touches[0].clientY);
  const onTouchEnd = () => handleEnd();

  const onMouseDown = (e: React.MouseEvent) => handleStart(e.clientX, e.clientY);
  const onMouseMove = (e: React.MouseEvent) => handleMove(e.clientX, e.clientY);
  const onMouseUp = () => handleEnd();
  const onMouseLeave = () => { if (isDragging) handleEnd(); };

  // Calculate rotation based on X drag
  const rotation = drag.x * 0.1;
  const opacity = Math.max(0, 1 - Math.abs(drag.x) / 1000); // Slight fade on extreme drag

  // Style logic
  const style: React.CSSProperties = isTop ? {
    transform: `translate(${drag.x}px, ${drag.y}px) rotate(${rotation}deg)`,
    transition: isDragging ? 'none' : 'transform 0.3s ease-out',
    cursor: isDragging ? 'grabbing' : 'grab',
    zIndex: 10,
    opacity
  } : {
    transform: 'scale(0.95) translateY(10px)',
    transition: 'transform 0.3s ease-out',
    zIndex: 5,
    opacity: 0.8,
    pointerEvents: 'none'
  };

  return (
    <div 
      ref={cardRef}
      className="absolute inset-0 bg-white rounded-3xl overflow-hidden shadow-xl border border-gray-100 select-none"
      style={style}
      onTouchStart={onTouchStart}
      onTouchMove={onTouchMove}
      onTouchEnd={onTouchEnd}
      onMouseDown={onMouseDown}
      onMouseMove={onMouseMove}
      onMouseUp={onMouseUp}
      onMouseLeave={onMouseLeave}
    >
      <div className="relative h-full flex flex-col">
        {/* SWIPE INDICATORS */}
        {isDragging && (
          <>
            <div 
              className="absolute top-8 left-8 border-4 border-green-500 rounded-lg px-4 py-2 transform -rotate-12 z-20 font-bold text-3xl text-green-500 tracking-widest bg-black/10 backdrop-blur-sm"
              style={{ opacity: drag.x > 20 ? Math.min(drag.x / 100, 1) : 0 }}
            >
              LIKE
            </div>
            <div 
              className="absolute top-8 right-8 border-4 border-red-500 rounded-lg px-4 py-2 transform rotate-12 z-20 font-bold text-3xl text-red-500 tracking-widest bg-black/10 backdrop-blur-sm"
              style={{ opacity: drag.x < -20 ? Math.min(Math.abs(drag.x) / 100, 1) : 0 }}
            >
              NOPE
            </div>
          </>
        )}

        <div className="relative flex-1">
          <img 
            src={profile.photos[0]} 
            alt={profile.name} 
            className="w-full h-full object-cover pointer-events-none"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent pointer-events-none"></div>

          {/* Top Actions */}
          <div className="absolute top-4 right-4 z-30" onMouseDown={e => e.stopPropagation()} onTouchStart={e => e.stopPropagation()}>
             <button onClick={() => onReport(profile)} className="p-2 bg-black/20 backdrop-blur-md rounded-full text-white hover:bg-black/40">
               <MoreVertical size={20} />
             </button>
          </div>

          {/* Real Photo Tag */}
          <div className="absolute top-4 left-4 bg-black/30 backdrop-blur-md px-3 py-1 rounded-full border border-white/20 flex items-center gap-1.5 z-30">
             <ShieldCheck size={12} className="text-green-400" />
             <span className="text-[10px] text-white font-bold tracking-wide uppercase">Foto Real</span>
          </div>

          {/* Bottom Info */}
          <div className="absolute bottom-0 left-0 w-full p-6 text-white pb-24 pointer-events-none">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="text-4xl font-heading font-bold shadow-black drop-shadow-md">{profile.name}, {profile.age}</h3>
              {profile.isVerified && <Badge type="verified">Verificado</Badge>}
            </div>
            <div className="flex items-center gap-1 text-gray-200 text-sm mb-3 font-medium">
              <MapPin size={16} className="text-brand-pink" />
              <span className="drop-shadow-md">{profile.district ? `${profile.district}, ` : ''}{profile.city}</span>
            </div>
            <p className="text-gray-100 text-sm line-clamp-3 opacity-95 leading-relaxed drop-shadow-sm">{profile.bio}</p>
          </div>
        </div>

        {/* Floating Action Buttons */}
        <div 
          className="absolute bottom-6 left-4 right-4 grid grid-cols-2 gap-4 z-40"
          onMouseDown={e => e.stopPropagation()} 
          onTouchStart={e => e.stopPropagation()}
        >
          <Button 
            variant="outline" 
            onClick={() => onDiscard(profile)} 
            className="bg-white/10 border-white/40 text-white hover:bg-white/20 hover:border-red-400 hover:text-red-400 backdrop-blur-md h-14 rounded-full"
          >
             <X size={24} />
             <span className="ml-2">Ignorar</span>
          </Button>
          <Button 
            variant="primary" 
            onClick={() => onChat(profile)}
            className="shadow-xl shadow-brand-pink/30 h-14 rounded-full bg-brand-pink"
          >
            <Heart size={24} className="fill-current" />
            <span className="ml-2">Gostar</span>
          </Button>
        </div>

        {/* "Encontro" floating button (secondary action) */}
        <div 
           className="absolute bottom-24 right-4 z-40"
           onMouseDown={e => e.stopPropagation()} 
           onTouchStart={e => e.stopPropagation()}
        >
           <button 
             onClick={() => onProposeDate(profile)}
             className="bg-white text-brand-blue p-3 rounded-full shadow-lg border border-blue-100 flex items-center gap-2 font-bold text-xs hover:scale-105 transition-transform"
           >
             <Calendar size={16} />
             Encontro
           </button>
        </div>
      </div>
    </div>
  );
};

export const Feed: React.FC = () => {
  const navigate = useNavigate();
  const [selectedProfile, setSelectedProfile] = useState<UserProfile | null>(null);
  const [isDateModalOpen, setDateModalOpen] = useState(false);
  const [isReportModalOpen, setReportModalOpen] = useState(false);

  // Location Filter State
  const [currentLocation, setCurrentLocation] = useState('Todas as Províncias');
  const [showLocationModal, setShowLocationModal] = useState(false);

  // Date Proposal State
  const [dateDetails, setDateDetails] = useState({ date: '', time: '', location: '' });

  // Visited/Discarded Profiles State
  const [viewedIds, setViewedIds] = useState<Set<string>>(new Set());

  // Load user preference on mount
  useEffect(() => {
    const saved = localStorage.getItem('txova_user_province');
    if (saved) setCurrentLocation(saved);
  }, []);

  const handleProposeDate = (profile: UserProfile) => {
    setSelectedProfile(profile);
    setDateModalOpen(true);
  };

  const handleSendDateProposal = () => {
    if (!selectedProfile) return;
    const msg = `Olá ${selectedProfile.name}! Gostaria de te convidar para um encontro no dia ${dateDetails.date} às ${dateDetails.time} no local: ${dateDetails.location}. O que achas?`;

    chatService.sendMessage(selectedProfile.id, msg);

    setDateModalOpen(false);
    navigate(`/chat/${selectedProfile.id}`);
  };

  const handleReport = (reasonId: string) => {
    alert("Obrigado. A denúncia foi enviada. Levamos a segurança muito a sério.");
    setReportModalOpen(false);
  };

  const handleDiscard = (profile: UserProfile) => {
    setViewedIds(prev => new Set(prev).add(profile.id));
  };

  const handleChat = (profile: UserProfile) => {
    // Like action - also removes from stack but navigates to chat
    // In a real app, this would create a "Match" first.
    navigate(`/chat/${profile.id}`);
  };

  const filteredProfiles = MOCK_PROFILES.filter(profile => {
    if (viewedIds.has(profile.id)) return false;
    if (currentLocation === 'Todas as Províncias') return true;
    return profile.city.includes(currentLocation) || (currentLocation.includes('Maputo') && profile.city.includes('Maputo'));
  });

  // We only render the top 2 profiles for performance and stacking effect
  const activeProfiles = filteredProfiles.slice(0, 2);

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] overflow-hidden bg-gray-50">
      {/* Top Bar */}
      <div className="px-4 py-4 flex items-center justify-between z-10">
        <h2 className="font-heading font-bold text-2xl text-gray-800">Descobrir</h2>

        <button 
          onClick={() => setShowLocationModal(true)}
          className="flex items-center gap-1 text-xs font-semibold text-brand-pink bg-white px-3 py-2 rounded-full border border-pink-100 shadow-sm"
        >
          <MapPin size={14} />
          <span className="max-w-[100px] truncate">{currentLocation}</span>
          <ChevronDown size={14} />
        </button>
      </div>

      {/* Card Stack Area */}
      <div className="flex-1 relative mx-4 mb-4">
        {activeProfiles.length > 0 ? (
          activeProfiles.map((profile, index) => (
            <ProfileCard 
              key={profile.id}
              profile={profile} 
              isTop={index === 0}
              onProposeDate={handleProposeDate}
              onReport={(p) => { setSelectedProfile(p); setReportModalOpen(true); }}
              onChat={handleChat}
              onDiscard={handleDiscard}
            />
          )).reverse() // Reverse to render the first item on TOP (z-index logic matches DOM order usually, but here we use explicit z-index)
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-8 bg-white rounded-3xl border border-gray-100 shadow-sm">
            <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
               <Heart className="text-gray-300" size={40} />
            </div>
            <h3 className="font-bold text-xl text-gray-800 mb-2">Sem mais perfis</h3>
            <p className="text-gray-500 text-sm mb-6">Não há mais ninguém em {currentLocation} por enquanto.</p>
            <button 
               onClick={() => { setViewedIds(new Set()); setCurrentLocation('Todas as Províncias'); }} 
               className="text-brand-pink font-bold text-sm bg-pink-50 px-6 py-3 rounded-full hover:bg-pink-100 transition-colors"
            >
              Ver todos novamente
            </button>
          </div>
        )}
      </div>

      {/* Date Proposal Modal */}
      <Modal isOpen={isDateModalOpen} onClose={() => setDateModalOpen(false)} title="Marcar Encontro">
        <div className="space-y-4">
          <p className="text-sm text-gray-500">Propõe uma data. O convite será enviado por chat privado.</p>
          <Input 
             label="Data" 
             type="date" 
             value={dateDetails.date} 
             onChange={e => setDateDetails({...dateDetails, date: e.target.value})}
          />
          <Input 
             label="Hora" 
             type="time" 
             value={dateDetails.time}
             onChange={e => setDateDetails({...dateDetails, time: e.target.value})}
          />
          <Input 
             label="Local Sugerido" 
             placeholder="Ex: Restaurante O Marisco" 
             value={dateDetails.location}
             onChange={e => setDateDetails({...dateDetails, location: e.target.value})}
          />
          <Button onClick={handleSendDateProposal}>Enviar Convite</Button>
        </div>
      </Modal>

      {/* Location Modal */}
      <Modal isOpen={showLocationModal} onClose={() => setShowLocationModal(false)} title="Selecionar Localização">
        <div className="grid grid-cols-1 gap-2 max-h-[60vh] overflow-y-auto">
           <button 
             onClick={() => { setCurrentLocation('Todas as Províncias'); setShowLocationModal(false); }}
             className={`p-3 rounded-xl text-left font-medium ${currentLocation === 'Todas as Províncias' ? 'bg-brand-pink text-white' : 'bg-gray-50 text-gray-700 hover:bg-gray-100'}`}
           >
             Todas as Províncias
           </button>
           {PROVINCES.map(prov => (
             <button 
               key={prov}
               onClick={() => { setCurrentLocation(prov); setShowLocationModal(false); }}
               className={`p-3 rounded-xl text-left font-medium ${currentLocation === prov ? 'bg-brand-pink text-white' : 'bg-gray-50 text-gray-700 hover:bg-gray-100'}`}
             >
               {prov}
             </button>
           ))}
        </div>
      </Modal>

      {/* Report Modal */}
      <Modal isOpen={isReportModalOpen} onClose={() => setReportModalOpen(false)} title="Denunciar Perfil">
        <div className="space-y-2">
           <p className="text-sm text-gray-500 mb-4">Se suspeitares que a foto não é real, denuncia imediatamente.</p>
           {REPORT_REASONS.map(reason => (
             <button 
               key={reason.id}
               onClick={() => handleReport(reason.id)}
               className="w-full text-left p-3 rounded-lg hover:bg-red-50 text-gray-700 hover:text-red-600 text-sm font-medium border border-transparent hover:border-red-100 transition-colors flex items-center justify-between"
             >
               {reason.label}
               <Flag size={14} />
             </button>
           ))}
        </div>
      </Modal>
    </div>
  );
};

