import React, { useState, useEffect } from 'react';
import { User, Heart, MessageCircle, GalleryVerticalEnd, Download, Megaphone, LogOut, Menu } from 'lucide-react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { authService } from '../services/auth';

interface LayoutProps {
  children: React.ReactNode;
}

export const Layout: React.FC<LayoutProps> = ({ children }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showDesktopMenu, setShowDesktopMenu] = useState(false);

  // Handle PWA Install Prompt
  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = async () => {
    if (deferredPrompt) {
      deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') {
        setDeferredPrompt(null);
      }
    } else {
      alert("Para instalar, use a opção 'Adicionar ao Ecrã Principal' do seu navegador.");
    }
  };

  // Hide nav on onboarding and chat screen (full screen experience on mobile)
  if (location.pathname === '/' || location.pathname === '/onboarding') {
    return <main className="min-h-screen bg-white">{children}</main>;
  }

  const isChatScreen = location.pathname.startsWith('/chat/');

  const navItems = [
    { icon: <GalleryVerticalEnd size={24} />, label: 'Descobrir', path: '/feed' },
    { icon: <Heart size={24} />, label: 'Gostos', path: '/likes' },
    { icon: <MessageCircle size={24} />, label: 'Chat', path: '/messages' },
    { icon: <Megaphone size={24} />, label: 'Anunciar', path: '/ads' },
    { icon: <User size={24} />, label: 'Perfil', path: '/profile' },
