import { Message, ChatSession } from '../types';
import { MOCK_PROFILES } from '../constants';
import { matchService } from './match';

let MOCK_MESSAGES: Record<string, Message[]> = {
  // Pre-seeded message for demo match
  'u2': [
    { id: 'm1', text: 'Parabéns pelo Match! 🎉', senderId: 'system', timestamp: Date.now() - 10000, isRead: false }
  ]
};

export const chatService = {
  getChats: (): ChatSession[] => {
    const matches = matchService.getMatches();
    const sessions: ChatSession[] = [];

    matches.forEach(match => {
      // Find the "other" user in the match
      const otherUserId = match.users.find(id => id !== 'me');
      if (!otherUserId) return;

      const user = MOCK_PROFILES.find(p => p.id === otherUserId);
      if (!user) return;

      const msgs = MOCK_MESSAGES[otherUserId] || [];
      const lastMsg = msgs.length > 0 ? msgs[msgs.length - 1] : { text: "Começa a conversa!", timestamp: match.createdAt };

      sessions.push({
        userId: user.id,
        userName: user.name,
        userPhoto: user.photos[0],
        lastMessage: lastMsg.text,
        lastMessageTime: lastMsg.timestamp,
        unreadCount: msgs.filter(m => !m.isRead && m.senderId !== 'me' && m.senderId !== 'system').length,
        matchId: match.id
      });
    });

    return sessions.sort((a, b) => b.lastMessageTime - a.lastMessageTime);
  },

  getMessages: (userId: string): Message[] => {
    // Security check: Only return messages if matched
    const matches = matchService.getMatches();
    const isMatched = matches.some(m => m.users.includes(userId));

    if (!isMatched) return [];

    return MOCK_MESSAGES[userId] || [];
  },

  sendMessage: (userId: string, text: string) => {
    const matches = matchService.getMatches();
    const isMatched = matches.some(m => m.users.includes(userId));
    if (!isMatched) {
        console.error("Cannot send message: Not matched.");
        return;
    }

    if (!MOCK_MESSAGES[userId]) {
      MOCK_MESSAGES[userId] = [];
    }

    const newMessage: Message = {
      id: Date.now().toString(),
      text,
      senderId: 'me',
      timestamp: Date.now(),
      isRead: true
    };

    MOCK_MESSAGES[userId].push(newMessage);

    // Simulate auto-reply
    setTimeout(() => {
      const reply: Message = {
        id: (Date.now() + 1).toString(),
        text: "Gostei de falar contigo! 😊",
        senderId: userId,
        timestamp: Date.now(),
        isRead: false
      };
      MOCK_MESSAGES[userId].push(reply);
    }, 2000);
  },

  markAsRead: (userId: string) => {
    if (MOCK_MESSAGES[userId]) {
      MOCK_MESSAGES[userId].forEach(m => {
        if (m.senderId !== 'me') m.isRead = true;
      });
    }
  }
};

